import java.io.*;
import java.util.*;

class Cache {
    private Map<String, Serializable> cacheMap;  // Store key-value pairs in a map for quick access
    public static final String CACHE_FILE = "cache.ser";   // File to store serialized data
    
    // Constructor
    public Cache() {
        this.cacheMap = new HashMap<String, Serializable>();
        
        try{ 
            FileInputStream fileIn = new FileInputStream(CACHE_FILE);
            ObjectInputStream in = new ObjectInputStream(fileIn);
            cacheMap = (HashMap) in.readObject(); // Read the map from disk and store it into cacheMap
            in.close();
            fileIn.close();
        }catch(IOException | ClassNotFoundException i){ 
            System.out.println("Cache: " + i);    // Handle IO and class not found exceptions
            return;
        }
        
        Runtime.getRuntime().addShutdownHook(new Thread() {   // Shutdown hook to serialize cacheMap on exit
          public void run() {
              try { 
                FileOutputStream fileOut = new FileOutputStream(CACHE_FILE);
                ObjectOutputStream out = new ObjectOutputStream(fileOut);
                out.writeObject(cacheMap);    // Write the map into disk for persistent storage
                out.close();
                fileOut.close();
              }catch(IOException i) {   // Handle IO exceptions
                  System.out.println("Cache: " + i); 
              }
          }
        });
    }
    
    public Serializable getValue(String key) {
        return cacheMap.getOrDefault(key, null);
    }
    
    public void putValue(String key, Serializable value) {
        cacheMap.put(key, value);
    }
}